#!/usr/bin/env bash
# workflow-2.sh — 慢性足底筋膜炎管理 SOP walkthrough for 足踝外科.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="足踝外科"
WORKFLOW="慢性足底筋膜炎管理"

usage() {
  cat <<EOF
workflow-2.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-2.sh             # interactive
  ./workflow-2.sh --dry-run
  ./workflow-2.sh --json
  ./workflow-2.sh --explain
  ./workflow-2.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "慢性足底筋膜炎管理" 工作流。

一句话: 从足底筋膜炎确诊到症状缓解的 3-6 月标准管理流程

入门 SOP 共 8 步, 失败模式自检 12 项。

相关心智模型:
  • 保守治疗优先于手术 (3-6 月黄金期): 90% 的足踝慢性病变不需要手术, 但很多医生 / 患者直接跳到手术决策, 跳过保守治疗黄金期.
  • 影像学发现 ≠ 临床症状原因 (跟着症状走): MRI 看到的「异常」很多跟患者主诉无关. 影像跟症状对不上时, 跟着症状走, 不是跟着影像走.

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**确认诊断** —"
  "**整体力学评估** — gait (步态) + 鞋具 (磨损模式 / 鞋楦) + 足弓 (高弓 vs 平足) + 小腿肌张力 (Silverskiöld 跟腱挛缩 / 腓肠肌单独挛缩)"
  "**启动多模式保守治疗 (Tier 1, 6 周)**:"
  "**4-6 周复诊评估反应**:"
  "**Tier 2 (Tier 1 失败 → 6-12 周)**:"
  "**Tier 3 (3 月 Tier 2 失败 → 6-12 月)**:"
  "**手术评估 (3-6 月规范保守完整失败)**:"
  "**术后康复**: 渐进负重 + 拉伸训练, 6-12 周"
)
declare -a FAILURE_MODES=(
  "**不查整体力学只在筋膜止点打封闭** → 失衡不解决, 复发"
  "**患者教育模糊「多休息」** → 依从性差"
  "**保守治疗 < 3 个月就跳手术** → 跳过自愈窗口"
  "**同一位置反复封闭 5+ 次** → 诱发筋膜萎缩 + 跟骨脂肪垫萎缩"
  "**不区分腓肠肌挛缩 vs 全跟腱挛缩** (Silverskiöld) → 拉伸方案错配"
  "**忽略鞋具 + 直接做手术** → 复发率高"
  "**Baxter's nerve 漏诊** → 患者跑遍科室"
  "**关键决策点**:"
  "Tier 1 → Tier 2: 4-6 周改善 < 50%"
  "Tier 2 → Tier 3: 12 周改善 < 50%"
  "Tier 3 → 手术评估: 3-6 月仍 < 50% 改善"
  "手术内镜 vs 腓肠肌松解: Silverskiöld 阳性 (跟腱挛缩) 优先腓肠肌松解"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-2-walkthrough"
fi
